console.log('base loaded!');
(function () {
  var mq = window.matchMedia("(max-width: 767px)");
  var headerTop = document.querySelector(".header-top");
  var searchShell = document.querySelector(".header-top-end");
  var toggleBtn = document.querySelector(".mobile-search-toggle");

  if (!headerTop || !toggleBtn || !searchShell) return;

  var searchInput = document.getElementById("search-input");

  function setExpanded(open) {
    toggleBtn.setAttribute("aria-expanded", open ? "true" : "false");
  }

  function closeSearch() {
    headerTop.classList.remove("header-top--search-active");
    setExpanded(false);
  }

  function openSearch() {
    headerTop.classList.add("header-top--search-active");
    setExpanded(true);
    if (searchInput) {
      searchInput.focus();
    }
  }

  toggleBtn.addEventListener("click", function () {
    if (!mq.matches) return;
    if (headerTop.classList.contains("header-top--search-active")) {
      closeSearch();
    } else {
      openSearch();
    }
  });

  document.addEventListener(
    "pointerdown",
    function (e) {
      if (!mq.matches || !headerTop.classList.contains("header-top--search-active")) {
        return;
      }
      if (searchShell.contains(e.target)) return;
      closeSearch();
    },
    true
  );

  mq.addEventListener("change", function (e) {
    if (!e.matches) {
      closeSearch();
    }
  });
})();

const menu = document.querySelector('.menu');
const menuSection = menu.querySelector('.menu-section');
const menuArrow = menu.querySelector('.menu-mobile-arrow');
const menuClosed = menu.querySelector('.menu-mobile-close');
const menuTrigger = document.querySelector('.menu-mobile-trigger');
const menuOverlay = document.querySelector('.overlay');
let subMenu;

menuSection.addEventListener('click', (e) => {
   if (!menu.classList.contains('active')) {
      return;
   }

   if (e.target.closest('.menu-item-has-children')) {
      const hasChildren = e.target.closest('.menu-item-has-children');
      showSubMenu(hasChildren);
   }
});

menuArrow.addEventListener('click', () => {
   hideSubMenu();
});

menuTrigger.addEventListener('click', () => {
   toggleMenu();
});

menuClosed.addEventListener('click', () => {
   toggleMenu();
});

menuOverlay.addEventListener('click', () => {
   toggleMenu();
});

function toggleMenu() {
   menu.classList.toggle('active');
   menuOverlay.classList.toggle('active');
}

function showSubMenu(hasChildren) {
   subMenu = hasChildren.querySelector('.menu-subs');
   subMenu.classList.add('active');
   subMenu.style.animation = 'slideLeft 0.5s ease forwards';
   const menuTitle = hasChildren.querySelector('i').parentNode.childNodes[0].textContent;
   menu.querySelector('.menu-mobile-title').innerHTML = menuTitle;
   menu.querySelector('.menu-mobile-header').classList.add('active');
}

function hideSubMenu() {
   subMenu.style.animation = 'slideRight 0.5s ease forwards';
   setTimeout(() => {
      subMenu.classList.remove('active');
   }, 300);

   menu.querySelector('.menu-mobile-title').innerHTML = '';
   menu.querySelector('.menu-mobile-header').classList.remove('active');
}

window.onresize = function () {
   if (this.innerWidth > 991) {
      if (menu.classList.contains('active')) {
         toggleMenu();
      }
   }
};

const categorySlider = document.querySelector("[data-category-slider]");
const categoryDots = document.querySelector("[data-category-dots]");
const categoryPrefersReducedMotion = window.matchMedia(
  "(prefers-reduced-motion: reduce)",
);

if (categorySlider && categoryDots) {
  const categoryCards = Array.from(
    categorySlider.querySelectorAll(".category-card"),
  );

  categoryCards.forEach((card, index) => {
    const dot = document.createElement("button");

    dot.type = "button";
    dot.className = "category-dot";
    dot.setAttribute("aria-label", `Show category ${index + 1}`);

    if (index === 0) {
      dot.classList.add("is-active");
      dot.setAttribute("aria-current", "true");
    }

    dot.addEventListener("click", () => {
      card.scrollIntoView({
        behavior: categoryPrefersReducedMotion.matches ? "auto" : "smooth",
        block: "nearest",
        inline: "center",
      });
    });

    categoryDots.appendChild(dot);
  });

  const dots = Array.from(categoryDots.querySelectorAll(".category-dot"));
  let animationFrame;

  const updateActiveDot = () => {
    const sliderCenter =
      categorySlider.scrollLeft + categorySlider.offsetWidth / 2;
    let activeIndex = 0;
    let closestDistance = Infinity;

    categoryCards.forEach((card, index) => {
      const cardCenter = card.offsetLeft + card.offsetWidth / 2;
      const distance = Math.abs(sliderCenter - cardCenter);

      if (distance < closestDistance) {
        closestDistance = distance;
        activeIndex = index;
      }
    });

    dots.forEach((dot, index) => {
      const isActive = index === activeIndex;

      dot.classList.toggle("is-active", isActive);

      if (isActive) {
        dot.setAttribute("aria-current", "true");
      } else {
        dot.removeAttribute("aria-current");
      }
    });
  };

  categorySlider.addEventListener(
    "scroll",
    () => {
      window.cancelAnimationFrame(animationFrame);
      animationFrame = window.requestAnimationFrame(updateActiveDot);
    },
    { passive: true },
  );

  window.addEventListener("resize", updateActiveDot);
}

const swiper = new Swiper('.swiper', {
    // Optional parameters
    direction: 'horizontal',
    loop: true,
  
    // If we need pagination
    pagination: {
      el: '.swiper-pagination',
    },
  
    // Navigation arrows
    navigation: {
      nextEl: '.swiper-button-next',
      prevEl: '.swiper-button-prev',
    },

    breakpoints: {
      768: {
        navigation: false
      }
    }
});
const reviewTrack = document.querySelector("[data-review-track]");
const reviewDots = document.querySelector("[data-review-dots]");
const reviewPrefersReducedMotion = window.matchMedia(
  "(prefers-reduced-motion: reduce)",
);

if (reviewTrack && reviewDots) {
  const reviewSlides = Array.from(
    reviewTrack.querySelectorAll(".customer-review__slide"),
  );
  let reviewDotButtons = Array.from(
    reviewDots.querySelectorAll(".customer-review__dot"),
  );
  let activeReviewIndex = 0;
  let reviewAnimationFrame;

  if (!reviewDotButtons.length) {
    reviewSlides.forEach((slide, index) => {
      const dot = document.createElement("button");

      dot.type = "button";
      dot.className = "customer-review__dot";
      dot.setAttribute("aria-label", `Show customer review ${index + 1}`);

      if (index === 0) {
        dot.classList.add("is-active");
        dot.setAttribute("aria-current", "true");
      }

      reviewDots.appendChild(dot);
    });

    reviewDotButtons = Array.from(
      reviewDots.querySelectorAll(".customer-review__dot"),
    );
  }

  reviewDotButtons.forEach((dot, index) => {
    dot.addEventListener("click", () => {
      const slide = reviewSlides[index];

      if (!slide) {
        return;
      }

      slide.scrollIntoView({
        behavior: reviewPrefersReducedMotion.matches ? "auto" : "smooth",
        block: "nearest",
        inline: "start",
      });
    });
  });

  const setActiveReviewDot = () => {
    const trackCenter = reviewTrack.scrollLeft + reviewTrack.offsetWidth / 2;
    let closestDistance = Infinity;

    reviewSlides.forEach((slide, index) => {
      const slideCenter = slide.offsetLeft + slide.offsetWidth / 2;
      const distance = Math.abs(trackCenter - slideCenter);

      if (distance < closestDistance) {
        closestDistance = distance;
        activeReviewIndex = index;
      }
    });

    reviewDotButtons.forEach((dot, index) => {
      const isActive = index === activeReviewIndex;

      dot.classList.toggle("is-active", isActive);

      if (isActive) {
        dot.setAttribute("aria-current", "true");
      } else {
        dot.removeAttribute("aria-current");
      }
    });
  };

  const goToReview = (index) => {
    const slide = reviewSlides[index];

    if (!slide) {
      return;
    }

    slide.scrollIntoView({
      behavior: reviewPrefersReducedMotion.matches ? "auto" : "smooth",
      block: "nearest",
      inline: "start",
    });
  };

  reviewTrack.addEventListener(
    "scroll",
    () => {
      window.cancelAnimationFrame(reviewAnimationFrame);
      reviewAnimationFrame = window.requestAnimationFrame(setActiveReviewDot);
    },
    { passive: true },
  );

  if (!reviewPrefersReducedMotion.matches) {
    window.setInterval(() => {
      goToReview((activeReviewIndex + 1) % reviewSlides.length);
    }, 4000);
  }
}

document.addEventListener("DOMContentLoaded", function () {
  const headings = document.querySelectorAll(
    "#main-content h2, #main-content h3",
  );

  if (!headings.length) {
    return;
  }

  if (!("IntersectionObserver" in window)) {
    headings.forEach(function (heading) {
      heading.classList.add("is-visible");
    });
    return;
  }

  const headingObserver = new IntersectionObserver(
    function (entries, observer) {
      entries.forEach(function (entry) {
        if (!entry.isIntersecting) {
          return;
        }

        entry.target.classList.add("is-visible");
        observer.unobserve(entry.target);
      });
    },
    {
      threshold: 0.2,
    },
  );

  headings.forEach(function (heading) {
    heading.classList.add("heading-reveal");
    headingObserver.observe(heading);
  });
});

